Greedy best-insertion evaluates every existing assignment plus one new empty slot, picking the assignment that minimizes the marginal cost increase; if none feasible, falls back to a fresh assignment (or the first accepting existing one when at capacity).}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for j := range oris {
		ori := oris[j]
		des := dess[j]
		shipID := total_ship + j

		bestMarginal := 1e18
		bestIdx := -1

		// Evaluate existing assignments
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			oldCost := assign.Cost
			if assign.AddShip(shipID, ori, des) {
				assign.GenRoute()
				if newCost := assign.Cost; newCost >= 0 {
					marginal := newCost - oldCost
					if marginal < bestMarginal {
						bestMarginal = marginal
						bestIdx = i
					}
				}
				// Revert the trial
				assign.RemoveShip(shipID)
				assign.GenRoute()
			}
		}

		// Evaluate a new empty assignment if capacity allows
		if dispatch.AssignsLen < MAXASSIGNS {
			newIdx := dispatch.AssignsLen
			assign := &dispatch.Assigns[newIdx]
			*assign = Assign{} // clean slate
			if assign.AddShip(shipID, ori, des) {
				assign.GenRoute()
				if newCost := assign.Cost; newCost >= 0 {
					marginal := newCost // baseline 0
					if marginal < bestMarginal {
						bestMarginal = marginal
						bestIdx = newIdx
					}
				}
				// Revert the trial
				assign.RemoveShip(shipID)
				assign.GenRoute()
			}
			*assign = Assign{} // keep it clean for future
		}

		applied := false

		// Apply the best insertion found
		if bestIdx >= 0 {
			if bestIdx == dispatch.AssignsLen {
				// New assignment slot
				assign := &dispatch.Assigns[dispatch.AssignsLen]
				*assign = Assign{}
				if assign.AddShip(shipID, ori, des) {
					assign.GenRoute()
					if assign.Cost >= 0 {
						dispatch.AssignsLen++
						applied = true
					} else {
						assign.RemoveShip(shipID)
						assign.GenRoute()
						*assign = Assign{}
					}
				}
			} else {
				assign := &dispatch.Assigns[bestIdx]
				if assign.AddShip(shipID, ori, des) {
					assign.GenRoute()
					if assign.Cost >= 0 {
						applied = true
					} else {
						assign.RemoveShip(shipID)
						assign.GenRoute()
					}
				}
			}
		}

		// Fallback when no improved insertion is found or application failed
		if !applied {
			inserted := false
			// Safe seed-style: prefer a fresh assignment first
			if dispatch.AssignsLen < MAXASSIGNS {
				assign := &dispatch.Assigns[dispatch.AssignsLen]
				*assign = Assign{}
				if assign.AddShip(shipID, ori, des) {
					assign.GenRoute()
					if assign.Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						assign.RemoveShip(shipID)
						assign.GenRoute()
						*assign = Assign{}
					}
				}
			}
			if !inserted {
				// At capacity – try to insert into first accepting existing assignment
				for i := 0; i < dispatch.AssignsLen; i++ {
					assign := &dispatch.Assigns[i]
					if assign.AddShip(shipID, ori, des) {
						assign.GenRoute()
						if assign.Cost >= 0 {
							inserted = true
							break
						}
						assign.RemoveShip(shipID)
						assign.GenRoute()
					}
				}
			}
			// If still not inserted, we skip (should never happen under normal constraints)
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

